create table dirkspzm32.s_send_bew (
    bew_id           number(*, 0) not null enable,
    firma_nr         number(3, 0),
    herkunft         varchar2(3 char),
    tabelle          varchar2(5 char),
    auf_id           number(*, 0),
    status           varchar2(3 char),
    aktion           varchar2(3 char),
    ma_status        varchar2(1 char),
    ma_s_grund       number(*, 5),
    ma_id            varchar2(20 char),
    lte_nr           varchar2(50 char),
    lhm_nr           varchar2(50 char),
    lagerort         varchar2(50 char),
    zlagerort        varchar2(50 char),
    menge            number(*, 3),
    menge_b          number(*, 3),
    schrott          number(*, 3),
    r_menge          number(*, 3),
    r_menge_b        number(*, 3),
    r_schrott        number(*, 3),
    stoerzeit_ist    number(*, 12),
    ruestzeit_ist    number(*, 12),
    prodzeit_ist     number(*, 12),
    ext_lief_nr      varchar2(20 char),
    ext_lief_pos     varchar2(5 char),
    charge           varchar2(60 char),
    serie            varchar2(20 char),
    arbeitsplatz_id  varchar2(20 char),
    ist_bestand      number(*, 5),
    artikel          varchar2(30 char),
    b_datum          date,
    lam_id           number(*, 0),
    lam_bh_id        number(*, 0),
    lam_bh_typ       varchar2(2 char),
    leitzahl         number(*, 5),
    fa_ag            number(*, 0),
    fa_upos          number(*, 0),
    lam_ag           number(*, 5),
    brutto_kg        number(*, 6),
    text             varchar2(250 char),
    err_nr           number(*, 5),
    user_name        varchar2(100 char),
    res_id           number(*, 0),
    send_id          number(*, 0),
    ma_last_s_grund  number(*, 5),
    pers_nr          number(*, 0),
    sper_grund       varchar2(30 char),
    lagerplatz       varchar2(30 char),
    zlagerplatz      varchar2(30 char),
    labor_status     varchar2(1 char),
    lam_sel1         varchar2(30 char),
    lam_sel2         varchar2(30 char),
    lam_sel3         varchar2(30 char),
    lam_sel4         varchar2(30 char),
    lam_sel5         varchar2(30 char),
    lam_sel6         varchar2(30 char),
    lam_sel7         varchar2(30 char),
    lam_sel8         varchar2(30 char),
    lam_sel9         varchar2(30 char),
    lam_sel10        varchar2(30 char),
    lte_name         varchar2(22 char),
    order_pos_auf_id number(*, 0),
    ruest_zeit_erf   number(*, 12),
    prod_zeit_erf    number(*, 12)
);

alter table dirkspzm32.s_send_bew
    add constraint pk_send_bew primary key ( bew_id )
        using index enable;


